+/// Match certificates with their private keys by `CKA_ID`.
+#[must_use]
+pub fn match_certificate_key_pairs(
+    certs: &[TokenCertificate],
+    keys: &[TokenKeyInfo],
+) -> Vec<CertificateKeyPair> {
+    let mut pairs = Vec::new();
+    for cert in certs {
+        if cert.is_ca || cert.id.is_empty() {
+            continue;
+        }
